Bug: graph edges are reversed. depends_on means 'this node depends on those', so edges should go from dependency to dependent.

def kahn_sort(tasks: list) -> list:
    graph = {}
    indegree = {}
    for t in tasks:
        nid = t['id']
        graph[nid] = []
        for dep in t['depends_on']:
            graph[dep].append(nid)
            indegree[nid] = indegree.get(nid, 0) + 1
    queue = [n for n in graph if indegree.get(n, 0) == 0]
    order = []
    while queue:
        node = queue.pop(0)
        order.append(node)
        for neighbor in graph.get(node, []):
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)
    return order

Fix: cycle detection returns wrong cycle path. It should return the actual cycle nodes.

```python
def find_cycle(graph: dict) -> list:
    visited = set()
    path = []
    def dfs(node):
        if node in visited:
            return path
        visited.add(node)
        path.append(node)
        for neighbor in graph.get(node, []):
            result = dfs(neighbor)
            if result:
                return result
        path.pop()
        return None
    for node in graph:
        result = dfs(node)
        if result:
            return result
    return []
```

Bug: visited set prevents re-entering nodes from different paths. Need separate 'in current path' tracking.

def find_cycle(graph: dict) -> list:
    path = []
    path_set = set()
    def dfs(node):
        path.append(node)
        path_set.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in path_set:
                result = dfs(neighbor)
                if result:
                    return result
            elif neighbor in path:
                cycle_start = path.index(neighbor)
                return path[cycle_start:]
        path.pop()
        path_set.discard(node)
        return None
    for node in graph:
        result = dfs(node)
        if result:
            return result
    return []

Fix: self-loop detection is missing.

```python
def has_cycle(graph: dict) -> bool:
    visited = set()
    rec_stack = set()
    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.discard(node)
        return False
    for node in graph:
        if node not in visited:
            if dfs(node):
                return True
    return False
```

This actually works for self-loops too since neighbor==node is in rec_stack. But it fails for nodes not in graph keys. Fix: ensure all referenced nodes are checked.

def has_cycle(graph: dict) -> bool:
    visited = set()
    rec_stack = set()
    all_nodes = set(graph.keys())
    for neighbors in graph.values():
        all_nodes.update(neighbors)

    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.discard(node)
        return False

    for node in all_nodes:
        if node not in visited:
            if dfs(node):
                return True
    return False

