Fix: topological sort with priority (lexicographic smallest) uses wrong data structure.

```python
def topo_sort_lex(graph: dict) -> list:
    """Return lexicographically smallest topological order."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    queue = sorted([n for n in graph if indeg[n] == 0])
    result = []
    while queue:
        node = queue.pop()
        result.append(node)
        for v in graph.get(node, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)
                queue.sort()
    return result
```

Bug: queue.pop() takes from the end (largest), should take from front (smallest).

def topo_sort_lex(graph: dict) -> list:
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    import heapq
    heap = sorted([n for n in graph if indeg[n] == 0])
    result = []
    while heap:
        node = heapq.heappop(heap)
        result.append(node)
        for v in graph.get(node, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                heapq.heappush(heap, v)
    return result

Fix: cycle detection returns True for undirected graph traversal revisiting parent.

```python
def has_cycle_undirected(adj: dict) -> bool:
    """Detect cycle in undirected graph."""
    visited = set()
    def dfs(node, parent):
        visited.add(node)
        for nb in adj.get(node, []):
            if nb not in visited:
                if dfs(nb, node):
                    return True
            elif nb != parent:
                return True
        return False
    for node in adj:
        if node not in visited:
            if dfs(node, None):
                return True
    return False
```

Bug: multi-edges between same two nodes give false positive. Parent check only works for single edge. Fix by tracking parent edge index instead.

def has_cycle_undirected(adj: dict) -> bool:
    """Detect cycle in undirected graph using edge index tracking."""
    visited = set()
    edge_stack = []

    def dfs(node, edge_idx):
        visited.add(node)
        for nb in adj.get(node, []):
            edge_key = (min(node, nb), max(node, nb))
            if edge_key not in edge_stack:
                edge_stack.append(edge_key)
                if nb not in visited:
                    if dfs(nb, edge_key):
                        return True
                elif nb != node:
                    if edge_key not in edge_stack:
                        return True
                edge_stack.pop()
            else:
                return True
        return False

    for node in adj:
        if node not in visited:
            edge_stack = []
            if dfs(node, (node, node)):
                return True
    return False

Fix: topo sort with iterative DFS has stack ordering bug.

```python
def iterative_topo(graph: dict) -> list:
    """Iterative DFS topological sort."""
    visited = set()
    result = []
    for start in graph:
        if start in visited:
            continue
        stack = [start]
        while stack:
            node = stack.pop()
            if node in visited:
                continue
            visited.add(node)
            result.append(node)
            for nb in graph.get(node, []):
                if nb not in visited:
                    stack.append(nb)
    return result
```

Bug: this is just DFS order, not topological order. Need to append after all children are processed.

def iterative_topo(graph: dict) -> list:
    visited = set()
    result = []
    for start in graph:
        if start in visited:
            continue
        stack = [(start, False)]
        while stack:
            node, done = stack.pop()
            if node in visited:
                continue
            if done:
                result.append(node)
                continue
            visited.add(node)
            stack.append((node, True))
            for nb in graph.get(node, []):
                if nb not in visited:
                    stack.append((nb, False))
    return result

