Fix: all-paths topo sort doesn't yield all valid orderings.

```python
def all_topo_sorts(graph: dict) -> list:
    """Return all valid topological orderings."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    results = []
    def backtrack(path):
        if len(path) == len(graph):
            results.append(path[:])
            return
        for n in graph:
            if indeg[n] == 0 and n not in path:
                indeg[n] = -1
                path.append(n)
                for v in graph[n]:
                    indeg[v] -= 1
                backtrack(path)
                path.pop()
                for v in graph[n]:
                    indeg[v] += 1
    backtrack([])
    return results
```

Bug: setting indeg[n] = -1 to mark as used, but should restore to 0 on backtrack, not just leave checks.

def all_topo_sorts(graph: dict) -> list:
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    results = []
    def backtrack(path):
        if len(path) == len(graph):
            results.append(path[:])
            return
        for n in sorted(indeg):
            if indeg[n] == 0 and n not in path:
                indeg[n] = -1
                path.append(n)
                for v in graph[n]:
                    indeg[v] -= 1
                backtrack(path)
                path.pop()
                for v in graph[n]:
                    indeg[v] += 1
                indeg[n] = 0
    backtrack([])
    return results

Fix: BFS shortest path returns path length instead of actual path.

```python
def bfs_path(graph: dict, start, end) -> list:
    """Return shortest path from start to end as list of nodes."""
    if start == end:
        return [start]
    visited = {start}
    queue = [(start, 0)]
    while queue:
        node, dist = queue.pop(0)
        for nb in graph.get(node, []):
            if nb == end:
                return dist + 1
            if nb not in visited:
                visited.add(nb)
                queue.append((nb, dist + 1))
    return []
```

Bug: returns integer distance instead of path. Need to track parent pointers.

def bfs_path(graph: dict, start, end) -> list:
    if start == end:
        return [start]
    visited = {start}
    parent = {start: None}
    queue = [start]
    while queue:
        node = queue.pop(0)
        for nb in graph.get(node, []):
            if nb not in visited:
                visited.add(nb)
                queue.append(nb)
                parent[nb] = node
                if nb == end:
                    path = []
                    curr = end
                    while curr in parent:
                        path.append(curr)
                        curr = parent[curr]
                    path.append(start)
                    return path[::-1]
    return []

