def kruskal_mst(n: int, edges: list) -> list:
    """Return MST edges. edges = [(u, v, w)]."""
    parent = list(range(n))
    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x
    def union(a, b):
        ra, rb = find(a), find(b)
        if ra != rb:
            parent[ra] = rb
            return True
        return False
    mst = []
