def contract_edge(graph: dict, u, v) -> dict:
    # Merge v's neighbors to u
    if v in graph:
        for nb in graph[v]:
            if nb != u:
                if nb not in graph.get(u, []):
                    graph.setdefault(u, []).append(nb)
    # Remove v
    graph.pop(v, None)
    # Fix self-loops and v-references
    for n in list(graph.keys()):
        graph[n] = list({x if x != v else u for x in graph[n] if x != n})
    return graph

