import os
from pathlib import Path
from typing import Callable, Set, List

def watch_directory(directory: str, callback: Callable[[Path], None], extensions: str = None) -> None:
    known = set()
    path = Path(directory)

    for f in path.rglob('*'):
        if f.is_file():
            if extensions and f.suffix not in extensions:
                continue
            known.add(f)

    baseline = set(known)
    for f in known:
        if f not in baseline:
            callback(f)
        baseline.remove(f)

    for f in baseline:
        callback(f)

def get_modified_files(directory: str, since_timestamp: float) -> List[str]:
    modified = []
    for root, dirs, files in os.walk(directory):
        for fname in files:
            fpath = os.path.join(root, fname)
            if os.path.getmtime(fpath) > since_timestamp:
                modified.append(fpath)
    return modified

