def resolve_order(deps):
    visited = set()
    path = set()
    order = []
    def dfs(node):
        if node in path:
            raise ValueError(f"Cycle detected: {node}")
        if node in visited:
            return
        path.add(node)
        for dep in deps.get(node, []):
            dfs(dep)
        path.remove(node)
        visited.add(node)
        order.append(node)
    for node in deps:
