class Trie:
    def __init__(self):
        self.root = {}
        self.words = set()

    def insert(self, word: str) -> None:
        node = self.root
        for c in word:
            if c not in node:
                node[c] = {}
            node = node[c]
        node['$'] = True
        self.words.add(word)

