def sanitize_html(html: str, allowed_tags: list = None) -> str:
    if allowed_tags is None:
        allowed_tags = ['b', 'i', 'em', 'strong', 'a', 'p', 'br']
    allowed_tags = set(t.lower() for t in allowed_tags)

    class SanitizeParser(HTMLParser):
        def __init__(self, allowed):
            super().__init__(convert_chardata=False)
            self.allowed = allowed
            self.result = []

        def handle_starttag(self, tag, attrs):
            t = tag.lower()
            if t in self.allowed:
                self.result.append(f'<{tag}>')
            else:
                self.result.append('')

        def handle_endtag(self, tag):
            t = tag.lower()
            if t in self.allowed:
                self.result.append(f'</{tag}>')
            else:
                self.result.append('')

        def handle_data(self, data):
            self.result.append(data)

        def handle_entityref(self, name):
            self.result.append(f'&#{name};')

    parser = SanitizeParser(allowed_tags)
    parser.feed(html)
    return ''.join(parser.result)

import re

def tokenize_expression(expr: str) -> list[dict]:
    tokens = []
    # Pattern: numbers (int/float), operators, parens
    pattern = r'(\d+\.?\d*|\.\d+|[+\-*/()])'
    matches = re.finditer(pattern, expr)
    for m in matches:
        val = m.group(1)
        if val in '+-*/()':
            tokens.append({'type': 'operator', 'value': val})
        elif val in '()':
            tokens.append({'type': 'paren', 'value': val})
        else:
            tokens.append({'type': 'number', 'value': val})
    return tokens

def rate_per_interval(events, interval, total_duration):
    import math
    intervals = []
    for i in range(math.ceil(total_duration / interval)):
        start = i * interval
        end = min((i + 1) * interval, total_duration)
        if start < end:
            count = sum(1 for e in events if start <= e['timestamp'] < end)
            intervals.append({'interval_start': start, 'interval_end': end, 'count': count})
    return intervals

class BatchProcessor:
    def __init__(self, batch_size: int):
        self.batch_size = batch_size
        self.current_batch = []
        self.completed_batches = []

    def add(self, item):
        self.current_batch.append(item)
        if len(self.current_batch) >= self.batch_size:
            self.completed_batches.append(self.current_batch)
            self.current_batch = []

    def flush(self):
        if self.current_batch:
            self.completed_batches.append(self.current_batch)
            self.current_batch = []
        return self.completed_batches

    def pending(self) -> int:
        return len(self.current_batch)

