class CacheWithTTL:
    def __init__(self, default_ttl: float):
        self.default_ttl = default_ttl
        self.entries: Dict[str, tuple] = {}  # key -> (value, expiry_time)

    def set(self, key: str, value: Any, ttl: Optional[float] = None):
        expiry = time.time() + (ttl or self.default_ttl)
        self.entries[key] = (value, expiry)

    def get(self, key: str, now: float = 0) -> Optional[Any]:
        if key not in self.entries:
            return None
        value, expiry = self.entries[key]
        if expiry <= now:
            del self.entries[key]
            return None
        return value

    def cleanup(self, now: float = 0):
        expired = [k for k, (value, expiry) in self.entries.items() if expiry <= now]
        for k in expired:
            del self.entries[k]

def partition_by_predicate(items: list, predicate) -> tuple[list, list]:
    matching = []
    not_matching = []
    for item in items:
        if predicate(item):
            matching.append(item)
        else:
            not_matching.append(item)
    return matching, not_matching

import re

def parse_dsn(dsn: str) -> dict:
    pattern = r'^(?P<driver>[\w-]+)://(?P<auth>[\w\@.+]+)@(?P<host>\S+):(?P<port>\d+)/(?P<db>\S+)(?:\?(?P<params>[^#]+))?$'
    m = re.match(pattern, dsn)
    if not m:
        raise ValueError(f'Invalid DSN: {dsn}')
    parts = m.groupdict()
    user, passw = parts['auth'].split(':', 1) if ':' in parts['auth'] else (parts['auth'], '')
    params = {}
    if parts['params']:
        for kv in parts['params'].split('&'):
            k, v = kv.split('=', 1)
            params[k] = v.lstrip('!') if '=' in kv else True
    return {
        'driver': parts['driver'],
        'user': user,
        'password': passw,
        'host': parts['host'],
        'port': parts['port'],
        'database': parts['db'],
        'params': params
    }

def find_all_paths(graph: dict, start: str, end: str) -> list:
    paths = []
    def dfs(node, path):
        if node == end:
            paths.append(path[:])
            return
        for nb in graph.get(node, []):
            path.append(nb)
            dfs(nb, path)
            path.pop()
    dfs(start, [start])
    return paths

def group_consecutive(values: list[int]) -> list[list[int]]:
    if not values:
        return []
    sorted_vals = sorted(values)
    groups = [[sorted_vals[0]]]
    for v in sorted_vals[1:]:
        if v == groups[-1][-1] + 1:
            groups[-1].append(v)
        else:
            groups.append([v])
    return groups

