from typing import Any, Callable

def memoize(func: Callable) -> Callable:
    cache: dict = {}
    @wraps(func)
    def wrapper(*args, **kwargs) -> Any:
        key = (args, tuple(sorted((k, v) for k, v in kwargs.items())))
        if key not in cache:
            cache[key] = func(*args, **kwargs)
        return cache[key]
    return wrapper

def knapsack_01(items: list[tuple[int, int]], capacity: int) -> tuple[int, list[int]]:
    n = len(items)
    dp = [[-1] * (capacity + 1) for _ in range(n + 1)]
    dp[0][0] = 0
    parent = [[None] * (capacity + 1) for _ in range(n + 1)]

    for i in range(1, n + 1):
        w, v = items[i - 1]
        for c in range(capacity + 1):
            if dp[i - 1][c] > dp[i][c]:
                dp[i][c] = dp[i - 1][c]
            elif w <= c and dp[i - 1][c - w] + v > dp[i][c]:
                dp[i][c] = dp[i - 1][c - w] + v
                parent[i][c] = (i - 1, c - w)

    c = capacity
    selected = []
    for i in range(n, 0, -1):
        if parent[i][c] is not None:
            _, prev_c = parent[i][c]
            selected.append(i - 1)
            c = prev_c
    selected.reverse()
    return dp[n][capacity], selected

