class TimeSeriesBuffer:
    def __init__(self, max_size: int):
        self.max_size = max_size
        self.points = deque()  # (timestamp, value)
        self.timestamps = deque()

    def add(self, timestamp: float, value: float):
        self.points.append((timestamp, value))
        self.timestamps.append(timestamp)
        if len(self.points) > self.max_size:
            self.points.popleft()
            self.timestamps.popleft()

    def query(self, start: float, end: float) -> list:
        result = []
        for ts, val in self.points:
            if start <= ts <= end:
                result.append((ts, val))
        return sorted(result, key=lambda x: x[0])

    def stats(self, start: float, end: float) -> dict:
        points = self.query(start, end)
        if not points:
            return {'count': 0, 'mean': 0.0, 'std': 0.0, 'min': 0.0, 'max': 0.0}
        vals = [v for _, v in points]
        n = len(vals)
        mean = sum(vals) / n
        variance = sum((x - mean) ** 2 for x in vals) / n if n > 1 else 0.0
        std = math.sqrt(variance)
        return {
            'count': n,
            'mean': mean,
            'std': std,
            'min': min(vals),
            'max': max(vals)
        }

