def parse_headers(raw: str) -> dict:
    lines = raw.replace('\r', '').split('\n')
    result = {}
    for line in lines:
        line = line.strip()
        if not line:
            continue
        if ':' in line:
            key, val = line.split(':', 1)
            key = key.strip()
            val = val.strip()
            if key in result and val.startswith('\t'):
                result[key] = result[key] + val[1:].strip()
            else:
                result[key] = val
    return result

import heapq

class PriorityMap:
    def __init__(self):
        self._data = {}
        self._heap = []

    def put(self, key: str, value, priority: int):
        self._data[key] = value
        # Push (-priority, key) for max-heap semantics
        heapq.heappush(self._heap, (-priority, key))

    def get(self, key: str):
        return self._data.get(key)

    def top(self, n: int = 1) -> list[tuple[str, any]]:
        result = []
        popped = 0
        while self._heap and popped < n:
            _, key = heapq.heappop(self._heap)
            if key in self._data:
                result.append((key, self._data[key]))
                del self._data[key]
                popped += 1
        return result

    def remove(self, key: str) -> bool:
        if key not in self._data:
            return False
        del self._data[key]
        return True

