def match_rules(data: dict, rules: list) -> list[str]:
    matched = []
    for rule in rules:
        field = rule['field']
        op = rule['operator']
        value = rule['value']
        if field not in data:
            continue
        val = data[field]
        if op == 'eq' and val == value:
            matched.append(rule['id'])
        elif op == 'ne' and val != value:
            matched.append(rule['id'])
        elif op == 'gt' and val > value:
            matched.append(rule['id'])
        elif op == 'lt' and val < value:
            matched.append(rule['id'])
        elif op == 'gte' and val >= value:
            matched.append(rule['id'])
        elif op == 'lte' and val <= value:
            matched.append(rule['id'])
        elif op == 'contains' and value in val:
            matched.append(rule['id'])
        elif op == 'in' and val in value if isinstance(value, list) else False:
            matched.append(rule['id'])
    return matched

def camel_to_snake(s: str) -> str:
