    return re.sub(r'([A-Z]+[a-z])', lambda m: m.group(1).lower(), s).replace('_', '_')

def matrix_multiply(a: list[list[float]], b: list[list[float]]) -> list[list[float]]:
    if not a or not b:
        return []
    rows_a, cols_a = len(a), len(a[0])
    rows_b, cols_b = len(b), len(b[0])
    if cols_a != rows_b:
        raise ValueError(f"Matrix dimension mismatch: {cols_a} != {rows_b}")
    result = [[0.0] * cols_b for _ in range(rows_a)]
    for i in range(rows_a):
        for j in range(cols_b):
            for k in range(cols_a):
                result[i][j] += a[i][k] * b[k][j]
    return result

def interleave(*lists):
    result = []
    # Get the maximum length
    max_len = max(len(lst) for lst in lists) if lists else 0
    for i in range(max_len):
        for lst in lists:
            if i < len(lst):
                result.append(lst[i])
    return result

def validate_password(password: str, rules: dict = None) -> dict:
    import string
    if rules is None:
        rules = {
            'min_length': 8,
            'require_upper': True,
            'require_lower': True,
            'require_digit': True,
            'require_special': True,
        }
    errors = []
    if len(password) < rules.get('min_length', 8):
        errors.append(f"Password too short (min {rules['min_length']})")
    if rules.get('require_upper', False) and not any(c.isupper() for c in password):
        errors.append("Missing uppercase letter")
    if rules.get('require_lower', False) and not any(c.islower() for c in password):
        errors.append("Missing lowercase letter")
    if rules.get('require_digit', False) and not any(c.isdigit() for c in password):
        errors.append("Missing digit")
    if rules.get('require_special', False) and not any(c in string.punctuation for c in password):
        errors.append("Missing special character")
    return {'valid': len(errors) == 0, 'errors': errors}

from typing import Dict, List
from collections import defaultdict

def pivot_table(rows: List[dict], index: str, column: str, value: str, agg: str = 'sum') -> dict:
    grouped = defaultdict(dict)
    for r in rows:
        idx = r[index]
        col = r[column]
        if col not in grouped[idx]:
            grouped[idx][col] = []
        grouped[idx][col].append(r[value])

    result = {}
    for idx in sorted(grouped.keys()):
        result[idx] = {}
        vals = grouped[idx]
        if agg == 'sum':
            result[idx] = {k: sum(vals[k]) for k in vals}
        elif agg == 'count':
            result[idx] = {k: len(vals[k]) for k in vals}
        elif agg == 'mean':
            result[idx] = {k: sum(vals[k])/len(vals[k]) if vals[k] else 0 for k in vals}
        else:
            result[idx] = vals
    return result

import re

def apply_transformations(data, transforms):
    import re
    result = data
    for t in transforms:
        if t['type'] == 'filter':
            result = [d for d in result if d.get(t['field']) == t['value']]
        elif t['type'] == 'map':
            result = [{**d, t['field']: eval(t['expr'], {**d, t['field']: d[t['field']]})} for d in result]
        elif t['type'] == 'sort':
            result = sorted(result, key=lambda d: d.get(t['field'], 0), reverse=t.get('reverse', False))
        elif t['type'] == 'limit':
            result = result[:t['count']]
    return result

import re

def parse_csv_line(line: str, delimiter: str = ',') -> list[str]:
    fields = []
    current = []
    in_quotes = False
    i = 0
    while i < len(line):
        c = line[i]
        if in_quotes:
            if c == '"':
                if i + 1 < len(line) and line[i + 1] == '"':
                    current.append('"')
                    i += 1
                else:
                    in_quotes = False
            else:
                current.append(c)
        else:
            if c == '"':
                in_quotes = True
            elif c == delimiter:
                fields.append(''.join(current))
                current = []
            else:
                current.append(c)
        i += 1
    fields.append(''.join(current))
    return fields

