def running_rank(values: list[float]) -> list[int]:
    if not values:
        return []
    ranks = []
    for i, v in enumerate(values):
        local_rank = 1 - sum(1 for prev in values[:i+1] if prev > v)
        ranks.append(local_rank)
    return ranks

def invert_dict(d: dict) -> dict:
    result = {}
    for k, v in d.items():
        if v not in result:
            result[v] = [k]
        else:
            result[v].append(k)
    return result

