def merge_intervals(intervals):
    if not intervals:
        return []
    sorted_intervals = sorted(intervals, key=lambda x: x[0])
    merged = [sorted_intervals[0]]
    for start, end in sorted_intervals[1:]:
        last = merged[-1]
        if start <= last[1]:
            merged[-1] = (last[0], max(last[1], end))
        else:
            merged.append((start, end))
    return merged

class EventEmitter:
    def __init__(self):
        self._listeners = {}  # event -> set of callbacks

    def on(self, event: str, callback):
        if event not in self._listeners:
            self._listeners[event] = set()
        self._listeners[event].add(callback)

    def off(self, event: str, callback):
        if event in self._listeners:
            self._listeners[event].discard(callback)
            if not self._listeners[event]:
                del self._listeners[event]

    def emit(self, event: str, *args, **kwargs) -> int:
        if event not in self._listeners:
            return 0
        count = 0
        for cb in list(self._listeners[event]):
            try:
                cb(*args, **kwargs)
                count += 1
            except Exception:
                pass
        return count

import re

def parse_size_string(s: str) -> int:
    """Convert human-readable size strings to bytes."""
    s = s.upper()
    match = re.match(r'^([\d.]+)\s*(B|KB|MB|GB|TB)$', s)
    if not match:
        raise ValueError(f"Invalid size string: {s}")
    value, unit = float(match.group(1)), match.group(2)
    multipliers = {'B': 1, 'KB': 1024, 'MB': 1024**2, 'GB': 1024**3, 'TB': 1024**4}
    return int(value * multipliers[unit])

def deduplicate_by_key(items: list[dict], key: str) -> list[dict]:
    seen = set()
    result = []
    for item in items:
        if item[key] not in seen:
            seen.add(item[key])
            result.append(item)
    return result

import re

def validate_email(email: str) -> bool:
    if not email or ' ' in email:
        return False
    if '@' not in email:
        return False
    parts = email.split('@')
    if len(parts) != 2 or not parts[0] or not parts[1]:
        return False
    local, domain = parts
    if len(email) > 254 or len(local) > 64:
        return False
    if '.' not in domain:
        return False
    if domain[0] in '-_' or domain[-1] in '-_':
        return False
    return bool(re.match(r'^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$', email))

import re

def validate_config(config: dict) -> list[str]:
    errors = []

    if 'name' not in config:
        errors.append("Missing required field 'name'")
        return errors

    name = config['name']
    if not isinstance(name, str) or not (1 <= len(name) <= 64) or not re.match(r'^[a-zA-Z0-9_-]+$', name):
        errors.append("Invalid 'name': must be alphanumeric with -/_, 1-64 chars")

    if 'port' in config:
        port = config['port']
        if not isinstance(port, int) or not (1 <= port <= 65535):
            errors.append("'port' must be int 1-65535")

    if 'hosts' not in config:
        errors.append("Missing required field 'hosts'")
    else:
        hosts = config['hosts']
        if not isinstance(hosts, list) or len(hosts) == 0:
            errors.append("'hosts' must be non-empty list")
        elif not all(isinstance(h, str) for h in hosts):
            errors.append("'hosts' list must contain only strings")

    if 'timeout' in config:
        timeout = config['timeout']
        if not isinstance(timeout, (int, float)) or timeout <= 0:
            errors.append("'timeout' must be positive number")

    if 'retry' in config:
        retry = config['retry']
        if not isinstance(retry, dict) or 'max' not in retry or 'delay' not in retry:
            errors.append("'retry' must be dict with 'max' and 'delay'")
        elif not (1 <= retry['max'] <= 10 or not isinstance(retry['max'], int)):
            errors.append("'retry.max' must be int 1-10")
        elif retry['delay'] <= 0 or not isinstance(retry['delay'], (int, float)):
            errors.append("'retry.delay' must be positive number")

    return errors

def normalize_phone(phone: str) -> str:
    import re
    # Extract digits and optional leading +
    digits = re.sub(r'[^\d+]', '', phone)
    if not digits.startswith('+'):
        if digits.startswith('1'):
            # US/CA: assume +1
            if len(digits) == 10:
                return '+' + digits
            elif len(digits) == 11 and digits[0] == '1':
                return '+' + digits
            else:
                raise ValueError(f"Unknown format: {phone}")
        elif digits.startswith('08'):
            # Japan: 080/090/070/050 -> +81
            if len(digits) == 11:
                return '+81' + digits[2:]
            raise ValueError(f"Unknown Japanese format: {phone}")
        else:
            raise ValueError(f"Unknown format: {phone}")
    else:
        # Already has +
        if len(digits) == 12 and digits[1] == '1':
            return '+' + digits[2:]
        return '+' + digits

class StateManager:
    def __init__(self, initial: str, transitions: dict[str, list[str]]):
        self.current = initial
