def deduplicate_by_key(
    items: List[Dict],
    key: str,
    window_seconds: Optional[float] = None,
    time_field: str = 'timestamp'
) -> List[Dict]:
    seen: dict = {}
    result: List[Dict] = []
    window_start: Optional[float] = None
    if window_seconds is not None:
        window_start = time.time()

    for item in items:
        k = item.get(key)
