def moving_zscore(values: List[float], window: int) -> List[float]:
    """Compute rolling z-score with fixed window."""
    if window <= 0:
        return [0.0] * len(values)
    result = []
    for i in range(len(values)):
        start = max(0, i - window + 1)
        window_vals = values[start:i + 1]
        if len(window_vals) < 2:
            result.append(0.0)
            continue
        mean = sum(window_vals) / len(window_vals)
        variance = sum((x - mean) ** 2 for x in window_vals) / len(window_vals)
        std = math.sqrt(variance) if variance > 0 else 0.0
        if std == 0.0:
            result.append(0.0)
        else:
            result.append((values[i] - mean) / std)
    return result

class Bag:
    def __init__(self):
        self._counts = {}

    def add(self, item, count=1):
        self._counts[item] = self._counts.get(item, 0) + count

    def remove(self, item, count=1):
        if item not in self._counts or self._counts[item] < count:
            return False
        self._counts[item] -= count
        if self._counts[item] == 0:
            del self._counts[item]
        return True

