from collections import deque

def sliding_window_max(values: list[float], window: int) -> list[float]:
    """Return sliding window maximums using monotonic deque."""
    if not values or window <= 0:
        return []
    if window > len(values):
        return [values[-1]]
    q = deque()
    result = []
    for i, v in enumerate(values):
        while q and values[q[-1]] <= v:
            q.pop()
        q.append(i)
        if i - q[0] >= window:
            q.popleft()
        result.append(values[q[0]])
    return result

