    if not nums:
        return ''
    s = sorted(set(nums))
    if not s:
        return ''
    start = end = s[0]
    parts = []
    for x in s[1:]:
        if x == end + 1:
            end = x
        else:
            parts.append(f'{start}-{end}' if start != end else str(start))
            start = end = x
    parts.append(f'{start}-{end}' if start != end else str(start))
    return ','.join(parts)

