    m = re.match(r'(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}) \[(\w+)\] (\w+): (.*)', line)
    if m:
        return {
            'timestamp': m.group(1),
            'level': m.group(2),
            'component': m.group(3),
            'message': m.group(4).strip()
        }
    return {'timestamp': '', 'level': '', 'component': '', 'message': ''}

import re

def parse_ini_section(text: str) -> dict:
    result = {}
    current = None
    for line in text.splitlines():
        line = line.strip()
        if not line or line.startswith('#') or line.startswith(';'):
            continue
        if line.startswith('[') and line.endswith(']'):
            current = line[1:-1].strip()
            result[current] = {}
            continue
        if '=' in line:
            key, val = line.split('=', 1)
            key = key.strip()
            val = val.strip().strip('"').strip("'")
            if current is None:
                current = '__DEFAULT__'
            result.setdefault(current, {})[key] = val
    return result

import heapq
from typing import List, Tuple, Optional

def shortest_path_with_waypoints(
    n: int,
    edges: List[Tuple[int, int, int]],
    start: int,
    end: int,
    waypoints: List[int]
) -> int:
    """
    Find minimum weight path from start to end visiting all waypoints (in any order).
    Return -1 if impossible.
    """
    if not edges:
        if start == end and not waypoints:
            return 0
        return -1

    # Build adjacency with min weight for each (u,v)
    adj: dict = {}
    for u, v, w in edges:
        if u not in adj:
            adj[u] = {}
        if v not in adj[u] or w < adj[u][v]:
            adj[u][v] = w
        elif w < adj[u][v]:
            adj[u][v] = w

    # Precompute all-pairs shortest between relevant nodes (start, end, waypoints)
    relevant = set([start, end]) | set(waypoints)
    relevant = list(relevant)
    if not relevant:
        return -1

    # Run Dijkstra from each relevant node to all nodes, but we only need distances to other relevant nodes
    # Since n <= 1000 and relevant <= 16, we can run Dijkstra from each relevant node
    dist_from: dict = {}
    for src in relevant:
        dist_from[src] = {}
        d = {node: float('inf') for node in range(n)}
        d[src] = 0
        pq = [(0, src)]
        while pq:
            dw, u = heapq.heappop(pq)
            if dw > d.get(u, float('inf')):
                continue
            if u not in adj:
                continue
            for v, w in adj[u].items():
                nd = dw + w
                if nd < d.get(v, float('inf')):
                    d[v] = nd
                    heapq.heappush(pq, (nd, v))
        dist_from[src] = {node: d[node] for node in relevant if node in d and d[node] < float('inf')}

    # Build distance matrix between relevant nodes
    relevant_set = set(relevant)
    rel_map = {node: i for i, node in enumerate(relevant)}
    matrix = [[float('inf')] * len(relevant) for _ in range(len(relevant))]
    for i, u in enumerate(relevant):
        for j, v in enumerate(relevant):
            if u in dist_from[u] and v in dist_from[u]:
                matrix[rel_map[u]][rel_map[v]] = dist_from[u][v]

    if not matrix[rel_map[start]][rel_map[end]]:
        return -1

    # DP with bitmask over waypoints
    # Map waypoints to 0..k-1
    unique_waypoints = sorted(list(set(waypoints)))
    wp_map = {node: i for i, node in enumerate(unique_waypoints)}
    k = len(unique_waypoints)
    if k == 0:
        # No waypoints, just shortest path start->end
        return matrix[rel_map[start]][rel_map[end]] if matrix[rel_map[start]][rel_map[end]] != float('inf') else -1

    # Check if start and end are in relevant and matrix is valid
    if matrix[rel_map[start]][rel_map[end]] == float('inf'):
        return -1

    # DP: dp[mask][i] = min cost to visit waypoints in mask, ending at waypoint i
    INF = 10**18
    dp = [[INF] * k for _ in range(1 << k)]
    # Initial: from start to each first waypoint
    for i in range(k):
        if matrix[rel_map[start]][rel_map[unique_waypoints[i]]] != INF:
            dp[1 << i][i] = matrix[rel_map[start]][rel_map[unique_waypoints[i]]]

    for mask in range(1, 1 << k):
        for last in range(k):
            if not (mask & (1 << last)):
                continue
            if dp[mask][last] == INF:
                continue
            new_mask = mask | (1 << last)
            # Try to go from last to next waypoint j not in mask
            for j in range(k):
                if new_mask & (1 << j):
                    continue
                if matrix[rel_map[unique_waypoints[last]]][rel_map[unique_waypoints[j]]] == INF:
                    continue
                new_cost = dp[mask][last] + matrix[rel_map[unique_waypoints[last]]][rel_map[unique_waypoints[j]]]
                if new_cost < dp[new_mask][j]:
                    dp[new_mask][j] = new_cost

    # Final step: from any last waypoint to end
    full_mask = (1 << k) - 1
    best = INF
    for last in range(k):
        if dp[full_mask][last] == INF:
            continue
        if matrix[rel_map[unique_waypoints[last]]][rel_map[end]] != INF:
            total = dp[full_mask][last] + matrix[rel_map[unique_waypoints[last]]][rel_map[end]]
            if total < best:
                best = total

    if best == INF:
        return -1
    return best

def count_longest_paths(n, edges, mod=10**9+7):
    """
    Count longest weighted paths in a DAG.
    Returns (length, count) or (-1, 0) if a cycle exists.
    """
    if n == 0:
        return (0, 0)

    # Build adjacency list and in-degree
    adj = [[] for _ in range(n)]
    indeg = [0] * n
    for u, v, w in edges:
        adj[u].append((v, w))
        indeg[v] += 1

    # Kahn's algorithm for topological sort
    queue = [i for i in range(n) if indeg[i] == 0]
    topo_order = []

    while queue:
        u = queue.pop(0)
        topo_order.append(u)
        for v, w in adj[u]:
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)

    # If we didn't process all nodes, there's a cycle
    if len(topo_order) < n:
        return (-1, 0)

    # DP for longest path and count
    dp_len = [0] * n
    dp_cnt = [1] * n  # Each source has one trivial path (length 0)

    for u in topo_order:
        for v, w in adj[u]:
            new_len = dp_len[u] + w
            if new_len > dp_len[v]:
                dp_len[v] = new_len
                dp_cnt[v] = dp_cnt[u]
            elif new_len == dp_len[v]:
                dp_cnt[v] = (dp_cnt[v] + dp_cnt[u]) % mod

    # Find the maximum length and its count
    max_len = max(dp_len)
    max_count = sum(dp_cnt[u] for u in range(n) if dp_len[u] == max_len) % mod

    return (max_len, max_count)

import bisect
from typing import Dict, List, Optional, Any

class VersionedKVStore:
    def __init__(self):
        self._versions: Dict[str, List[Optional[Any]]] = {}
        self._snapshots: Dict[int, Dict] = {}
        self._version_counter = 0
        self._next_version = 1

    def put(self, key: str, value: Any) -> int:
        self._version_counter += 1
        self._next_version = self._version_counter
        if key not in self._versions:
            self._versions[key] = []
        self._versions[key].append(value)
        return self._next_version

    def get(self, key: str, snap_id: Optional[int] = None) -> Optional[Any]:
        if key not in self._versions:
            return None
        if snap_id is None:
            return self._versions[key][-1]
        if snap_id not in self._snapshots:
            return None
        snapshot = self._snapshots[snap_id]
        if key in snapshot:
            return snapshot[key]
        return None

    def delete(self, key: str) -> bool:
        if key not in self._versions:
            return False
        self._version_counter += 1
        self._next_version = self._version_counter
        if key in self._versions:
            self._versions[key].append(None)
        return True

    def snapshot(self) -> int:
        snap_id = len(self._snapshots) + 1
        self._snapshots[snap_id] = dict(self._versions)
        return snap_id

    def rollback(self, snap_id: int):
        if snap_id not in self._snapshots:
            raise KeyError(f"Invalid snapshot id: {snap_id}")
        self._snapshots = {sid: data for sid, data in self._snapshots.items() if sid <= snap_id}
        self._versions = dict(self._snapshots[snap_id])

    def keys(self, snap_id: Optional[int] = None) -> List[str]:
        if snap_id is None:
            return sorted(self._versions.keys())
        if snap_id not in self._snapshots:
            raise KeyError(f"Invalid snapshot id: {snap_id}")
        return sorted(self._snapshots[snap_id].keys())

