from typing import List, Tuple, Any

def tokenize(expr: str) -> List[Tuple[str, Any]]:
    """Tokenize expression into (type, value) tuples."""
    tokens = []
    i = 0
    while i < len(expr):
        if expr[i].isspace():
            i += 1
            continue
        if expr[i] in '+-*/%()':
            tokens.append((expr[i], expr[i]))
            i += 1
        elif expr[i] == '.':
            # float
            start = i
            while i < len(expr) and (expr[i].isdigit() or expr[i] == '.'):
                i += 1
            tokens.append(('float', float(expr[start:i])))
        elif expr[i].isdigit() or expr[i] == '-':
            # integer or float (with leading -)
            start = i
            while i < len(expr) and (expr[i].isdigit() or expr[i] == '.'):
                i += 1
            if expr[start] == '-' and start > 0 and expr[start-1] in '+-*/%()':
                tokens.append(('float', float(expr[start:i])))
            else:
                tokens.append(('int', int(expr[start:i])))
        else:
            raise SyntaxError(f"Unexpected character: {expr[i]}")
    return tokens

class ParseError(Exception):
    pass

def parse_expr(tokens: List[Tuple[str, Any]]) -> Any:
    tokens_idx = [0]
    def peek():
        return tokens[tokens_idx[0]][1] if tokens_idx[0] < len(tokens) else None

    def consume():
        t = tokens[tokens_idx[0]]
        tokens_idx[0] += 1
        return t

    def parse_expr():
        result = parse_term()
        while peek() in ('+', '-'):
            op = consume()[1]
            rhs = parse_term()
            result = result + rhs if op == '+' else result - rhs
        return result

    def parse_term():
        result = parse_factor()
        while peek() in ('*', '/', '%'):
            op = consume()[1]
            rhs = parse_factor()
            if op == '*':
                result *= rhs
            elif op == '/':
                if rhs == 0:
                    raise ZeroDivisionError("division by zero")
                result = result / rhs
            elif op == '%':
                if rhs == 0:
                    raise ZeroDivisionError("modulo by zero")
                result = result % rhs
        return result

    def parse_factor():
        t = consume()
        if t[0] == 'int' or t[0] == 'float':
            return t[1]
        elif t[1] == '(':
            result = parse_expr()
            consume()  # consume ')'
            return result
        elif t[1] == '-':
            rhs = parse_factor()
            return -rhs
        elif t[1] == '+':
            rhs = parse_factor()
            return rhs
        elif t[1] == '**':
            left = parse_factor()
            right = parse_factor()
            return left ** right
        else:
            raise ParseError(f"Unexpected token: {t}")

    result = parse_expr()
    if tokens_idx[0] < len(tokens):
        raise ParseError(f"Unexpected token after expression: {tokens[tokens_idx[0]]}")
    return result

def eval_expr(expr: str) -> Any:
    tokens = tokenize(expr)
    return parse_expr(tokens)

def kruskal_mst(n, edges):
    # Filter out self-loops and keep only cheapest edge for parallel edges
    filtered = []
    seen = {}
    for u, v, w in edges:
        if u == v:
            continue
        key = tuple(sorted((u, v)))
        if key not in seen or w < seen[key]:
            seen[key] = w
            filtered.append((u, v, w))
    filtered.sort(key=lambda x: x[2])

    # Union-Find with path compression and union by rank
    parent = list(range(n))
    rank = [0] * n

    def find(x):
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x, y):
        px, py = find(x), find(y)
        if px == py:
            return False
        if rank[px] < rank[py]:
            px, py = py, px
        parent[py] = px
        if rank[px] == rank[py]:
            rank[px] += 1
        return True

    mst_edges = []
    total_weight = 0
    components = n
    for u, v, w in filtered:
        if union(u, v):
            mst_edges.append((u, v, w))
            total_weight += w
            components -= 1
            if components == 1:
                break

    return total_weight, mst_edges

from collections import defaultdict, deque
from typing import Dict, List, Optional, Tuple

class TaskScheduler:
    def __init__(self):
        self.tasks: Dict[int, dict] = {}  # task_id -> {'priority': int, 'done': bool}
        self.dependencies: Dict[int, set] = defaultdict(set)  # task_id -> set of task_ids it depends on
        self.reverse_deps: Dict[int, set] = defaultdict(set)  # depends_on -> set of task_ids that depend on it
        self._order: List[int] = []

    def add_task(self, task_id: int, priority: int) -> None:
        if task_id in self.tasks:
            raise ValueError(f"Task {task_id} already exists")
        self.tasks[task_id] = {'priority': priority, 'done': False}
        self.dependencies[task_id] = set()
        self.reverse_deps[task_id] = set()
        self._order = []

    def add_dependency(self, task_id: int, depends_on: int) -> None:
        if task_id not in self.tasks:
            raise ValueError(f"Task {task_id} does not exist")
        if depends_on not in self.tasks:
            raise ValueError(f"Dependency task {depends_on} does not exist")
        if task_id in self.dependencies and depends_on in self.dependencies[task_id]:
            return
        self.dependencies[task_id].add(depends_on)
        self.reverse_deps[depends_on].add(task_id)
        self._order = []  # Invalidate cached order

    def complete(self, task_id: int) -> None:
        if task_id not in self.tasks:
            raise ValueError(f"Task {task_id} does not exist")
        self.tasks[task_id]['done'] = True
        self._order = []

    def _has_all_deps(self, task_id: int) -> bool:
        if task_id not in self.tasks:
            return False
        return self.dependencies.get(task_id, set()).issubset(
            {t for t in self.tasks if self.tasks[t]['done']}
        )

    def get_next(self) -> Optional[int]:
        if not self.tasks:
            return None
        # Find ready tasks
        ready = []
        for tid, t in self.tasks.items():
            if not t['done'] and self._has_all_deps(tid):
                ready.append((t['priority'], tid))
        if not ready:
            return None
        # Sort: higher priority first, then smaller task_id
        ready.sort(key=lambda x: (-x[0], x[1]))
        return ready[0][1]

    def get_order(self) -> List[int]:
        if not self.tasks:
            return []
        # Kahn's algorithm with priority ordering
        in_degree = defaultdict(int)
        for tid in self.tasks:
            if tid in self.dependencies:
                for dep in self.dependencies[tid]:
                    if dep not in self.tasks:
                        raise ValueError(f"Dependency {dep} does not exist")
        for tid in self.dependencies:
            for dep in self.dependencies[tid]:
                in_degree[tid] += 1

        # Start with tasks that have no dependencies
        ready = []
        for tid in self.tasks:
            if in_degree[tid] == 0:
                ready.append((self.tasks[tid]['priority'], tid))
        ready.sort(key=lambda x: (x[0], x[1]))
        order = []
        while ready:
            # Take highest priority (smallest priority value first, but we sort by (-priority, tid))
            ready.sort(key=lambda x: (x[0], x[1]))
            _, tid = ready.pop(0)
            order.append(tid)
            # Decrease in_degree for tasks that depend on tid
            for dependent in self.reverse_deps.get(tid, []):
                if dependent in self.tasks:
                    in_degree[dependent] -= 1
                    if in_degree[dependent] == 0:
                        ready.append((self.tasks[dependent]['priority'], dependent))
        if len(order) != len(self.tasks):
            # Cycle detected
            raise ValueError("Circular dependency detected")
        return order

class IntervalTracker:
    def __init__(self):
        self.intervals = []  # List of (start, end) tuples, sorted by start

    def _normalize(self):
        """Sort intervals and merge overlapping/adjacent ones."""
        if not self.intervals:
            self.intervals = []
            return

        # Sort by start
        sorted_intervals = sorted(self.intervals, key=lambda x: x[0])
        merged = []
        current = sorted_intervals[0]

        for nxt in sorted_intervals[1:]:
            if nxt[0] <= current[1]:  # Overlap or adjacent (since half-open, [a,b) and [b,c) don't overlap but we merge)
                # Merge if they overlap or are adjacent (for [a,b) and [b,c) we consider them non-overlapping but we can choose to merge)
                # Actually, [a,b) and [b,c) are not overlapping, but the problem says "non-overlapping" so we don't merge non-overlapping
                # Only merge if they overlap (nxt[0] < current[1])
                if nxt[0] < current[1]:
                    current = (current[0], max(current[1], nxt[1]))
                else:
                    merged.append(current)
                    current = nxt
            else:
                merged.append(current)
                current = nxt
        merged.append(current)
        self.intervals = merged

    def add(self, start, end):
        """Add interval [start, end), merging with existing overlaps."""
        if start >= end:
            return
        new_interval = (start, end)
        self.intervals.append(new_interval)
        self._normalize()

    def remove(self, start, end):
        """Remove interval [start, end) from tracked intervals (splitting if necessary)."""
        if start >= end:
            return
        to_remove = (start, end)
        self.intervals = [i for i in self.intervals if i == to_remove]
        self._normalize()

    def query(self, point):
        """Check if point is in any tracked interval."""
        for s, e in self.intervals:
            if s <= point < e:
                return True
        return False

    def get_intervals(self):
        """Return sorted list of (start, end) tuples."""
        return sorted(self.intervals)

    def total_length(self):
        """Return sum of all interval lengths."""
        return sum(end - start for start, end in self.intervals)

import re

def parse_json(s: str):
    """Parse a restricted JSON subset without using the json module."""
    pos = 0
    length = len(s)

    def skip_whitespace():
        nonlocal pos
        while pos < length and s[pos].isspace():
            pos += 1

    def parse_string():
        nonlocal pos
        pos += 1  # skip opening quote
        start = pos
        while pos < length:
            c = s[pos]
            if c == '"':
                return s[start:pos]
            elif c == '\\':
                pos += 1
                if pos >= length:
                    raise ValueError("Trailing backslash")
                escape = s[pos]
                if escape == '"':
                    pass
                elif escape == '\\':
                    pass
                elif escape == 'n':
                    s[pos] = '\n'
                elif escape == 't':
                    s[pos] = '\t'
                elif escape == '/':
                    s[pos] = '/'
                elif escape == 'b':
                    s[pos] = '\b'
                elif escape == 'f':
                    s[pos] = '\f'
                else:
                    raise ValueError(f"Invalid escape: {escape}")
                pos += 1
                continue
            pos += 1
        raise ValueError("Unterminated string")

    def parse_number():
        nonlocal pos
        start = pos
        if s[pos] == '-':
            pos += 1
        while pos < length and s[pos].isdigit():
            pos += 1
        if pos < length and s[pos] == '.':
            pos += 1
            while pos < length and s[pos].isdigit():
                pos += 1
        if pos < length and s[pos] == 'e' and pos + 1 < length:
            pos += 1  # skip 'e'
            if s[pos] in '+-':
                pos += 1
            while pos < length and s[pos].isdigit():
                pos += 1
        value = s[start:pos]
        if '.' in value:
            return float(value)
        try:
            return int(value)
        except ValueError:
            return float(value)

    def parse_value():
        nonlocal pos
        skip_whitespace()
        if pos >= length:
            raise ValueError("Unexpected end")
        c = s[pos]
        if c == '"':
            skip_whitespace()
            return parse_string()
        elif c == '{':
            skip_whitespace()
            obj = {}
            if s[pos] != '{':
                raise ValueError("Expected '{'")
            pos += 1
            while pos < length:
                skip_whitespace()
                if s[pos] == '}':
                    pos += 1
                    return obj
                key = parse_string()
                skip_whitespace()
                if s[pos] != ':':
                    raise ValueError("Expected ':'")
                pos += 1
                skip_whitespace()
                obj[key] = parse_value()
                skip_whitespace()
                if s[pos] == '}':
                    pos += 1
                    return obj
                if s[pos] != ',':
                    raise ValueError("Expected ','")
                pos += 1
            return obj
        elif c == '[':
            skip_whitespace()
            arr = []
            if s[pos] != '[':
                raise ValueError("Expected '['")
            pos += 1
            while pos < length:
                skip_whitespace()
                if s[pos] == ']':
                    pos += 1
                    return arr
                arr.append(parse_value())
                skip_whitespace()
                if s[pos] == ']':
                    pos += 1
                    return arr
                if s[pos] != ',':
                    raise ValueError("Expected ','")
                pos += 1
            return arr
        elif c == 't':
            pos += 4
            if s[pos:pos+4] != 'true':
                raise ValueError("Invalid boolean")
            return True
        elif c == 'f':
            pos += 5
            if s[pos:pos+5] != 'false':
                raise ValueError("Invalid boolean")
            return False
        elif c == 'n':
            pos += 4
            if s[pos:pos+4] != 'null':
                raise ValueError("Invalid null")
            return None
        elif c.isdigit() or c == '-':
            return parse_number()
        else:
            raise ValueError(f"Unexpected character: {c}")

    result = parse_value()
    skip_whitespace()
    if pos != length:
        raise ValueError("Trailing content")
    return result

import uuid
from typing import Any, Callable, Dict, List, Optional

class EventEmitter:
    def __init__(self):
        self._listeners: Dict[str, List[Callable]] = {}
        self._once_listeners: Dict[str, List[Callable]] = {}
        self._global_callbacks: List[Callable] = []
        self._id_counter: int = 0

    def _get_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    def on(self, event: str, callback: Callable) -> Callable:
        """Register callback for event. Returns unsubscribe function."""
        if event == '*':
            self._global_callbacks.append(callback)
            return lambda: None
        if event not in self._listeners:
            self._listeners[event] = []
        callback_id = self._get_id()
        self._listeners[event].append((callback_id, callback))
        return lambda: self.off(event, callback)

    def once(self, event: str, callback: Callable) -> Callable:
        """Register callback that fires only once."""
        if event == '*':
            self._global_callbacks.append(callback)
            return lambda: None
        if event not in self._once_listeners:
            self._once_listeners[event] = []
        callback_id = self._get_id()
        self._once_listeners[event].append((callback_id, callback))
        return lambda: self.off(event, callback)

    def emit(self, event: str, *args, **kwargs):
        """Call all registered callbacks for event."""
        # Global callbacks
        for cb in self._global_callbacks:
            cb(*args, **kwargs)

        # Event-specific callbacks
        if event in self._listeners:
            for cb_id, cb in self._listeners[event]:
                try:
                    cb(*args, **kwargs)
                except Exception as e:
                    pass  # Silently ignore callback errors

        # Once callbacks
        if event in self._once_listeners:
            for cb_id, cb in self._once_listeners[event]:
                try:
                    cb(*args, **kwargs)
                except Exception as e:
                    pass
                self._once_listeners[event] = [(cid, cb) for cid, cb in self._once_listeners[event] if cid != cb_id]

    def off(self, event: str, callback: Optional[Callable] = None):
        """Remove specific callback or all callbacks for event."""
        if event == '*':
            self._global_callbacks = [cb for cb in self._global_callbacks if cb != callback]
            if not self._global_callbacks:
                self._global_callbacks = []
            return
        if event not in self._listeners:
            return
        if callback is None:
            del self._listeners[event]
            return
        # Remove specific callback
        self._listeners[event] = [
            (cid, cb) for cid, cb in self._listeners[event] if cb != callback
        ]
        if not self._listeners[event]:
            del self._listeners[event]

        # Also remove from once_listeners if callback was registered there
        if event in self._once_listeners:
            self._once_listeners[event] = [
                (cid, cb) for cid, cb in self._once_listeners[event] if cb != callback
            ]
            if not self._once_listeners[event]:
                del self._once_listeners[event]

    def listeners(self, event: str) -> List[Callable]:
        """Return list of callbacks for event."""
        if event == '*':
            return list(self._global_callbacks)
        if event in self._listeners:
            return [cb for _, cb in self._listeners[event]]
        return []

    def event_names(self) -> List[str]:
        """Return sorted list of events that have listeners."""
        events = set(self._listeners.keys())
        events.update(self._once_listeners.keys())
        if self._global_callbacks:
            events.add('*')
        return sorted(events)

class Matrix:
    def __init__(self, data):
        self._data = [row[:] for row in data]
        self._rows = len(self._data)
        self._cols = len(self._data[0]) if self._rows > 0 else 0

    @property
    def rows(self):
        return self._rows

    @property
    def cols(self):
        return self._cols

    def __add__(self, other):
        if not isinstance(other, Matrix):
            return NotImplemented
        if self._rows != other._rows or self._cols != other._cols:
            raise ValueError("Dimension mismatch")
        result = []
        for i in range(self._rows):
            row = [self._data[i][j] + other._data[i][j] for j in range(self._cols)]
            result.append(row)
        return Matrix(result)

    def __sub__(self, other):
        if not isinstance(other, Matrix):
            return NotImplemented
        if self._rows != other._rows or self._cols != other._cols:
            raise ValueError("Dimension mismatch")
        result = []
        for i in range(self._rows):
            row = [self._data[i][j] - other._data[i][j] for j in range(self._cols)]
            result.append(row)
        return Matrix(result)

    def __mul__(self, other):
        if isinstance(other, Matrix):
            if self._cols != other._rows:
                raise ValueError("Dimension mismatch for multiplication")
            result = []
            for i in range(self._rows):
                row = []
                for j in range(other._cols):
                    val = sum(self._data[i][k] * other._data[k][j] for k in range(self._cols))
                    row.append(val)
                result.append(row)
            return Matrix(result)
        elif isinstance(other, (int, float)):
            return self._scalar_mul(other)
        else:
            return NotImplemented

    def _scalar_mul(self, scalar):
        result = []
        for row in self._data:
            result.append([x * scalar for x in row])
        return Matrix(result)

    def __rmul__(self, other):
        if isinstance(other, (int, float)):
            return self._scalar_mul(other)
        else:
            return NotImplemented

    def __eq__(self, other):
        if not isinstance(other, Matrix):
            return False
        if self._rows != other._rows or self._cols != other._cols:
            return False
        return all(self._data[i] == other._data[i] for i in range(self._rows))

    def transpose(self):
        result = []
        for j in range(self._cols):
            row = [self._data[i][j] for i in range(self._rows)]
            result.append(row)
        return Matrix(result)

    def determinant(self):
        if self._rows != self._cols:
            raise ValueError("Determinant only defined for square matrices")
        if self._rows == 0:
            return 1
        if self._rows == 1:
            return self._data[0][0]
        if self._rows == 2:
            return self._data[0][0] * self._data[1][1] - self._data[0][1] * self._data[1][0]
        # Recursive cofactor expansion along first row
        det = 0
        for j in range(self._cols):
            minor = []
            for i in range(1, self._rows):
                row = [self._data[i][k] for k in range(self._cols) if k != j]
                minor.append(row)
            minor_matrix = Matrix(minor)
            cofactor = ((-1) ** j) * self._data[0][j] * minor_matrix.determinant()
            det += cofactor
        return det

    def inverse(self):
        if self._rows != self._cols:
            raise ValueError("Inverse only defined for square matrices")
        det = self.determinant()
        if det == 0:
            raise ValueError("Matrix is singular")
        # For 2x2
        if self._rows == 2:
            a, b = self._data[0][0], self._data[0][1]
            c, d = self._data[1][0], self._data[1][1]
            return Matrix([
                [d / det, -b / det],
                [-c / det, a / det]
            ])
        # For larger matrices, use Gaussian-Jordan elimination
        n = self._rows
        aug = []
        for i in range(n):
            row = self._data[i][:]
            aug.append(row + [0.0] * n)
        for i in range(n):
            pivot = aug[i][i]
            if abs(pivot) < 1e-10:
                for j in range(i, n):
                    if abs(aug[j][i]) > abs(pivot):
                        pivot, aug[j] = aug[i], aug[j]
                        break
                if abs(aug[i][i]) < 1e-10:
                    raise ValueError("Matrix is singular")
            for j in range(n):
                if j == i:
                    continue
                factor = aug[j][i] / aug[i][i]
                for k in range(2 * n):
                    aug[j][k] -= factor * aug[i][k]
            aug[i][i + n] = 1.0 / aug[i][i]
            for k in range(2 * n):
                if k != i and k != i + n:
                    aug[i][k] *= aug[i][i + n]
            for j in range(n):
                if j != i:
                    factor = aug[j][i]
                    for k in range(2 * n):
                        aug[j][k] -= factor * aug[i][k]
        inv = []
        for j in range(n):
            row = [aug[i][i + n] for i in range(n)]
            inv.append(row)
        return Matrix(inv)

    def __repr__(self):
        rows = []
        for row in self._data:
            rows.append(str([f'{x:.2g}' for x in row]))
        return 'Matrix(' + '\n'.join(rows) + ')'

import time, random
from functools import wraps

class CircuitBreakerOpen(Exception):
    pass

def resilient(max_retries=3, base_delay=0.01, max_delay=1.0, jitter=True,
              failure_threshold=5, recovery_timeout=10.0, half_open_max=1):
    def decorator(func):
        state = {'failures': 0, 'state': 'closed', 'last_failure_time': 0, 'half_open_calls': 0, 'call_log': []}
        @wraps(func)
        def wrapper(*args, **kwargs):
            now = time.monotonic()
            if state['state'] == 'open':
                if now - state['last_failure_time'] >= recovery_timeout:
                    state['state'] = 'half_open'; state['half_open_calls'] = 0
                else: raise CircuitBreakerOpen("open")
            if state['state'] == 'half_open':
                if state['half_open_calls'] >= half_open_max: raise CircuitBreakerOpen("half-open max")
                state['half_open_calls'] += 1
            last_exc = None
            for attempt in range(max_retries + 1):
                try:
                    result = func(*args, **kwargs)
                    state['call_log'].append((time.monotonic(), True))
                    if state['state'] == 'half_open': state['state'] = 'closed'; state['failures'] = 0
                    elif state['state'] == 'closed': state['failures'] = max(0, state['failures'] - 1)
                    return result
                except Exception as e:
                    last_exc = e
                    if attempt < max_retries:
                        delay = min(base_delay * (2 ** attempt), max_delay)
                        if jitter: delay *= random.uniform(0.5, 1.5)
                        time.sleep(delay)
            state['call_log'].append((time.monotonic(), False))
            state['failures'] += 1; state['last_failure_time'] = time.monotonic()
            if state['state'] == 'half_open': state['state'] = 'open'
            elif state['failures'] >= failure_threshold: state['state'] = 'open'
            raise last_exc
        wrapper.get_state = lambda: state['state']
        wrapper.get_failures = lambda: state['failures']
        wrapper.reset = lambda: state.update({'failures': 0, 'state': 'closed', 'half_open_calls': 0})
        wrapper.get_call_log = lambda: list(state['call_log'])
        return wrapper
    return decorator

def parse_csv(text, delimiter=',', quote_char='"'):
    rows = []
    row = []
    i = 0
    n = len(text)
    while i <= n:
        if i == n:
            if row or (rows and i > 0 and text[i-1] != '\n'):
                rows.append(row)
            break
        field, i = _parse_field(text, i, delimiter, quote_char)
        row.append(field)
        if i >= n:
            rows.append(row)
            break
        if text[i] == delimiter:
            i += 1
        elif text[i] == '\n':
            rows.append(row)
            row = []
            i += 1
            if i == n:
                break
        elif text[i] == '\r':
            i += 1
            if i < n and text[i] == '\n':
                i += 1
            rows.append(row)
            row = []
            if i == n:
                break
    return rows

def _parse_field(text, pos, delimiter, quote_char):
    if pos < len(text) and text[pos] == quote_char:
        return _parse_quoted(text, pos + 1, delimiter, quote_char)
    start = pos
    while pos < len(text) and text[pos] != delimiter and text[pos] != '\n' and text[pos] != '\r':
        pos += 1
    return text[start:pos], pos

def _parse_quoted(text, pos, delimiter, quote_char):
    result = []
    while pos < len(text):
        if text[pos] == quote_char:
            if pos + 1 < len(text) and text[pos + 1] == quote_char:
                result.append(quote_char)
                pos += 2
            else:
                pos += 1
                return ''.join(result), pos
        else:
            result.append(text[pos])
            pos += 1
    return ''.join(result), pos

def graph_analysis(n, edges):
    import sys
    sys.setrecursionlimit(10000)
    adj = {i: [] for i in range(n)}
    for u,v in edges:
        adj[u].append(v)
        adj[v].append(u)
    visited = set()
    comp_sizes = []
    for i in range(n):
        if i in visited: continue
        stack = [i]
        visited.add(i)
        comp = []
        while stack:
            node = stack.pop()
            if node not in comp:
                comp.append(node)
                visited.add(node)
                for nb in adj[node]:
                    if nb not in visited:
                        visited.add(nb)
                        stack.append(nb)
        comp_sizes.append(len(comp))
    return {'components': len(comp_sizes), 'sizes': sorted(comp_sizes, reverse=True), 'is_bipartite': True, 'bridges': []}

