def parse_ini(text: str) -> dict:
    result = {}
    section = None
    for line in text.split('\n'):
        line = line.strip()
        if not line or line[0] in ' #;':
            continue
        if line.startswith('[') and line.endswith(']'):
            section = line[1:-1].strip()
            result[section] = {}
            continue
        if '=' in line:
            k, v = line.split('=', 1)
            k = k.strip()
            v = v.strip()
            if section is None:
                section = ''
            result.setdefault(section, {})[k] = v
    return result

def deep_copy(obj, memo=None):
    if memo is None: memo = {}
    if id(obj) in memo: return memo[id(obj)]
    if isinstance(obj, dict):
        return {k: deep_copy(v, memo) for k, v in obj.items()}
    if isinstance(obj, list):
        return [deep_copy(x, memo) for x in obj]
    return obj

def two_sum(nums, target):
    seen = {}
    for i, num in enumerate(nums):
        need = target - num
        if need in seen:
            return [seen[need], i]
        if num not in seen:
            seen[num] = i
    return []

def max_subarray(nums):
    if not nums:
        return 0
    best = current = nums[0]
    for num in nums[1:]:
        current = max(num, current + num)
        best = max(best, current)
    return best

def merge_intervals(intervals):
    if not intervals:
        return []
    intervals = sorted(intervals, key=lambda x: x[0])
    merged = [intervals[0][:]]
    for start, end in intervals[1:]:
        last = merged[-1]
        if start <= last[1]:
            last[1] = max(last[1], end)
        else:
            merged.append([start, end])
    return merged

def climb_stairs(n):
    if n <= 0:
        return 0
    if n <= 2:
        return n
    a, b = 1, 2
    for _ in range(3, n + 1):
        a, b = b, a + b
    return b

def search_insert(nums, target):
    left, right = 0, len(nums)
    while left < right:
        mid = (left + right) // 2
        if nums[mid] < target:
            left = mid + 1
        else:
            right = mid
    return left

def coin_change(coins, amount):
    if amount == 0:
        return 0
    dp = [amount + 1] * (amount + 1)
    dp[0] = 0
    for total in range(1, amount + 1):
        for coin in coins:
            if coin <= total:
                dp[total] = min(dp[total], dp[total - coin] + 1)
    return -1 if dp[amount] > amount else dp[amount]

def product_except_self(nums):
    n = len(nums)
    if n == 0:
        return []
    result = [1] * n
    for i in range(1, n):
        result[i] = result[i - 1] * nums[i - 1]
    suffix = 1
    for i in range(n - 1, -1, -1):
        result[i] *= suffix
        suffix *= nums[i]
    return result

def longest_common_prefix(strs):
    if not strs:
        return ''
    prefix = strs[0]
    for s in strs[1:]:
        while not s.startswith(prefix):
            prefix = prefix[:-1]
            if not prefix:
                return ''
    return prefix

def compress_string(s):
    if not s:
        return ''
    parts = []
    count = 1
    for i in range(1, len(s) + 1):
        if i < len(s) and s[i] == s[i - 1]:
            count += 1
        else:
            parts.append(s[i - 1] + str(count))
            count = 1
    return ''.join(parts)

